from prometheus_client import start_http_server, Summary, Counter

# Create a new metric for each unique user-path combination
user_path_metrics = {}

def track_request(user_id, session_id, request_path):
    # Create a unique metric name based on user and path
    metric_name = f"user_{user_id}_{request_path}"

    # Check if the metric already exists
    if metric_name not in user_path_metrics:
        # Create a new metric if it doesn't
        user_path_metrics[metric_name] = Counter(metric_name, "HTTP requests by user and path")

    # Increment the metric for the specific user and path
    user_path_metrics[metric_name].inc()

# Start the Prometheus HTTP server
start_http_server(8000)

# Register the request tracking function with Prometheus
from flask import request
from flask_prometheus_client import metrics

@metrics.counter(
    "total_requests",
    "Total number of HTTP requests",
    labels={"user_id": lambda: request.headers.get("user_id"),
             "session_id": lambda: request.headers.get("session_id"),
             "request_path": lambda: request.path}
)
def track_total_requests():
    track_request(request.headers.get("user_id"), request.headers.get("session_id"), request.path)

